-- STEP 1: query [kommuner]
SELECT omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Drammen%';

-- STEP BOUNDARY --

-- STEP 2: query [flomsoner]
SELECT omrade FROM flomsoner.flomsoner_92001766ec964ab8b545fef0a00e6d23.flomareal WHERE gjentaksintervall = 200;

-- STEP BOUNDARY --

-- STEP 3: query [matrikkeleneiendomskartteig]
SELECT teig.geom AS parcel_geom, teig.objid AS parcel_id, teig.areal AS area FROM matrikkeleneiendomskartteig.matrikkeleneiendomskartteig_gis.teig AS teig JOIN (SELECT omrade FROM flomsoner.flomsoner_92001766ec964ab8b545fef0a00e6d23.flomareal WHERE gjentaksintervall = 200) AS flood_zones ON ST_Intersects(teig.geom, flood_zones.omrade) WHERE teig.areal > 5000;
